// Gate: hanya lanjut kalau JAM SEKARANG (WIB) memang terjadwal untuk profile ini
// sesuai settings di halaman Schedule web (dayConfigs per hari — jadwal rekomendasi).
// Kalau tidak terjadwal → return [] → seluruh cabang berhenti, tidak generate apa-apa.
const d = $input.first().json;
const settings = d.settings ?? {};
const jobs = d.jobs ?? [];

const now = new Date();
const wibHour = Number(now.toLocaleString("en-US", { timeZone: "Asia/Jakarta", hour: "2-digit", hour12: false })) % 24;
const wibDay = new Date(now.getTime() + 7 * 3600 * 1000).getUTCDay();

if (!settings.enabled) return [];
if (!(settings.days ?? []).includes(wibDay)) return [];

const dayConfig = settings.dayConfigs?.[wibDay] ?? {
  times: settings.times ?? [], carouselTimes: [],
  voice: settings.voice, useKnowledge: settings.useKnowledge, igShareToFeed: settings.igShareToFeed,
};

let isVideoTime = (dayConfig.times ?? []).includes(wibHour);
let isCarouselTime = (dayConfig.carouselTimes ?? []).includes(wibHour);
if (!isVideoTime && !isCarouselTime) return [];

// Anti-duplikat: kalau job dengan tipe sama sudah dibuat < 55 menit lalu, skip
const cutoff = Date.now() - 55 * 60 * 1000;
const recent = (t) => jobs.some(j => j.mediaType === t && new Date(j.createdAt).getTime() > cutoff);
if (isVideoTime && recent("video")) isVideoTime = false;
if (isCarouselTime && recent("carousel")) isCarouselTime = false;
if (!isVideoTime && !isCarouselTime) return [];

// Jadwal rekomendasi tidak pernah menumpuk video & carousel di jam sama —
// tapi kalau terjadi, video didahulukan.
const mediaType = isVideoTime ? "video" : "carousel";
return [{ json: {
  mediaType,
  voice: dayConfig.voice ?? "id-ID-ArdiNeural",
  useKnowledge: dayConfig.useKnowledge ?? true,
  igShareToFeed: dayConfig.igShareToFeed ?? true,
  autoTikTok: settings.autoTikTok ?? false,
  autoInstagram: settings.autoInstagram ?? false,
} }];

// Topik acak dari trending — server sudah memfilter topik yang pernah dibuat
// (memory AI), jadi selalu beda dengan konten sebelumnya.
const topics = $input.first().json.topics ?? [];
if (!topics.length) throw new Error("Trends Creavoo kosong");
const gate = $("Gate Jadwal Creavoo").first().json;
return [{ json: { ...gate, topic: topics[Math.floor(Math.random() * topics.length)], profile: "creavoo" } }];

// Parse SSE /api/generate → event "done" = script final. Event "error" = AI
// menolak (misal judul duplikat dengan konten lama).
const raw = String($input.first().json.data ?? "");
let script = null, errMsg = null;
for (const line of raw.split("\n")) {
  const t = line.trim();
  if (!t.startsWith("data:")) continue;
  try {
    const evt = JSON.parse(t.slice(5).trim());
    if (evt.type === "done") script = evt.data;
    if (evt.type === "error") errMsg = evt.message;
  } catch { /* token progress */ }
}

const pick = $("Pilih Topik Creavoo").first().json;
if (!script) {
  return [{ json: { ok: false, profile: "creavoo", topic: pick.topic, error: errMsg ?? "AI tidak mengembalikan script" } }];
}

// Body render sesuai tipe dari jadwal. Auto-upload flags dari settings profile —
// setelah render selesai, server otomatis publish ke akun sesuai profile + kirim
// SATU notif Telegram "Notif Post baru nih!" berisi link post.
const base = "https://creavoo-factory.vercel.app";
let renderUrl, renderBody;
if (pick.mediaType === "video") {
  renderUrl = base + "/api/render";
  renderBody = {
    ...script, layout: "auto", voice: pick.voice,
    watermarkHandle: "", watermarkLogoUrl: null, profile: "creavoo",
    autoTikTok: pick.autoTikTok, autoInstagram: pick.autoInstagram, igShareToFeed: pick.igShareToFeed,
  };
} else {
  renderUrl = base + "/api/render-image";
  renderBody = {
    ...script, layout: "auto", type: "carousel",
    totalSlides: (script.tips?.length ?? 5) + 2, style: "creavoo",
    watermarkHandle: "", watermarkLogoUrl: null,
    autoInstagram: pick.autoInstagram,
  };
}
return [{ json: { ok: true, profile: "creavoo", mediaType: pick.mediaType, topic: pick.topic, title: script.videoTitle, renderUrl, renderBody } }];

