// Susun ringkasan rencana konten HARI INI (WIB) untuk kedua profile, dari
// settings jadwal masing-masing (dayConfigs per hari). Judul konten belum ada
// di jam 8 pagi karena AI baru generate script tepat di jam produksinya —
// jadi yang ditampilkan tipe konten (Video/Reels atau Carousel) + jam produksi.
const names = ["Minggu", "Senin", "Selasa", "Rabu", "Kamis", "Jumat", "Sabtu"];
const now = new Date();
const wibDay = new Date(now.getTime() + 7 * 3600 * 1000).getUTCDay();
const hariName = names[wibDay];

function planFor(resp, label) {
  const s = resp?.settings ?? {};
  if (!s.enabled) return `${label}\ncontent : (schedule OFF, tidak ada rencana hari ini)\n`;
  if (!(s.days ?? []).includes(wibDay)) return `${label}\ncontent : (hari libur, tidak ada jadwal)\n`;

  const dc = s.dayConfigs?.[wibDay] ?? { times: s.times ?? [], carouselTimes: [] };
  const items = [];
  for (const h of (dc.times ?? [])) {
    const pf = [];
    if (s.autoTikTok) pf.push("TikTok");
    if (s.autoInstagram) pf.push("Instagram");
    items.push({ type: "Video/Reels", hour: h, pf });
  }
  for (const h of (dc.carouselTimes ?? [])) {
    const pf = [];
    if (s.autoInstagram) pf.push("Instagram");
    items.push({ type: "Carousel", hour: h, pf });
  }
  items.sort((a, b) => a.hour - b.hour);

  if (!items.length) return `${label}\ncontent : (hari evaluasi mingguan, tidak ada posting)\n`;

  let out = `${label}\n`;
  items.forEach((it, i) => {
    out += `content : ${it.type}\n`;
    out += `platform : ${it.pf.join(" / ") || "-"}\n`;
    out += `Produksi & posting : jam ${String(it.hour).padStart(2, "0")}:00 WIB\n`;
    if (i < items.length - 1) out += "\n";
  });
  return out;
}

const creavoo = $("Ambil Jadwal Creavoo (Digest)").first().json;
const zap = $input.first().json;

const text =
  `📅 RENCANA KONTEN SOSMED HARI ${hariName}\n\n` +
  planFor(creavoo, "Creavoo") + "\n" +
  planFor(zap, "zaportfolio") + "\n" +
  `Source : https://creavoo-factory.vercel.app`;

return [{ json: { text } }];

// Susun hasil evaluasi kedua profile jadi satu pesan Telegram.
const c = $("Evaluasi Creavoo").first().json;
const z = $input.first().json;

function block(label, r) {
  if (!r?.ok) return `${label}\n⚠️ Evaluasi gagal: ${r?.error ?? "unknown"}\n`;
  const status = r.applied ? "✅ Jadwal minggu depan diperbarui" : "ℹ️ Jadwal dipertahankan (data belum cukup / tidak berubah)";
  return `${label} (${r.postsAnalyzed ?? 0} post dianalisis)\n${r.narrative}\n${status}\n`;
}

const text =
  `📊 EVALUASI MINGGUAN\n\n` +
  block("Creavoo", c) + "\n" +
  block("Zaportfolio", z) + "\n" +
  `Cek/atur manual di Schedule: https://creavoo-factory.vercel.app/schedule`;

return [{ json: { text } }];
